inputs.code:
def main(args):
    import json
    from datetime import datetime

    preferences         = args.params.get('preferences', '')
    destinations        = args.params.get('destinations', '')
    weather_info        = args.params.get('weather_info', '')
    itinerary           = args.params.get('itinerary', '')
    culture_guide       = args.params.get('culture_guide', '')
    visa_info           = args.params.get('visa_info', '')
    accommodation_options = args.params.get('accommodation_options', '')
    restaurant_guide    = args.params.get('restaurant_guide', '')
    transport_plan      = args.params.get('transport_plan', '')
    event_calendar      = args.params.get('event_calendar', '')
    health_safety_info  = args.params.get('health_safety_info', '')
    shopping_guide      = args.params.get('shopping_guide', '')
    photography_guide   = args.params.get('photography_guide', '')
    budget_data_raw     = args.params.get('budget_data', '{}')

    try:
        bd = json.loads(budget_data_raw) if isinstance(budget_data_raw, str) else budget_data_raw
    except:
        bd = {'budget_breakdown': {}, 'budget_analysis': {}, 'packing_list': {}}

    sep = '━' * 75

    guide = f"""
╔═══════════════════════════════════════════════════════════════════════════╗
║                   ✈️  YOUR DREAM VACATION TRAVEL GUIDE  🌴                ║
║                     Generated: {datetime.now().strftime('%B %d, %Y at %H:%M')}                  ║
╚═══════════════════════════════════════════════════════════════════════════╝

🎯 YOUR TRAVEL PROFILE
{sep}
{preferences}


🌍 RECOMMENDED DESTINATIONS
{sep}
{destinations}


☀️ WEATHER & CLIMATE GUIDE
{sep}
{weather_info}


📋 VISA & ENTRY REQUIREMENTS
{sep}
{visa_info}


🏥 HEALTH & SAFETY BRIEFING
{sep}
{health_safety_info}


🏨 ACCOMMODATION OPTIONS
{sep}
{accommodation_options}


📅 YOUR DETAILED DAY-BY-DAY ITINERARY
{sep}
{itinerary}


🎉 EVENTS & FESTIVALS CALENDAR
{sep}
{event_calendar}


🍽️ FOOD & RESTAURANT GUIDE
{sep}
{restaurant_guide}


🚆 TRANSPORT PLAN
{sep}
{transport_plan}


🛍️ SHOPPING & SOUVENIRS GUIDE
{sep}
{shopping_guide}


📸 PHOTOGRAPHY & BEST SPOTS
{sep}
{photography_guide}


🏛️ CULTURAL INSIGHTS & LOCAL TIPS
{sep}
{culture_guide}


💰 BUDGET BREAKDOWN
{sep}
"""

    for cat, amt in bd.get('budget_breakdown', {}).items():
        guide += f"{cat:.<45} {amt:>12}\n"

    an = bd.get('budget_analysis', {})
    guide += f"""

📊 BUDGET ANALYSIS:
   Your Budget:      {an.get('your_budget', 'N/A')}
   Estimated Cost:   {an.get('estimated_cost', 'N/A')}
   Difference:       {an.get('difference', 'N/A')}
   Status:           {an.get('status', 'N/A')}
   Daily Spending:   {an.get('daily_spending', 'N/A')}
   Travel Tier:      {an.get('tier', 'N/A')}

"""
    guide += "💡 MONEY-SAVING TIPS:\n"
    for tip in bd.get('money_tips', []):
        guide += f"   {tip}\n"

    guide += f"""


🎒 COMPLETE PACKING LIST
{sep}

📋 ESSENTIALS:\n"""
    for item in bd.get('packing_list', {}).get('essentials', []):
        guide += f"   {item}\n"
    guide += "\n👕 CLOTHING:\n"
    for item in bd.get('packing_list', {}).get('clothing', []):
        guide += f"   {item}\n"
    guide += "\n🎁 EXTRAS & ACCESSORIES:\n"
    for item in bd.get('packing_list', {}).get('extras', []):
        guide += f"   {item}\n"

    guide += f"""


✅ PRE-DEPARTURE CHECKLIST
{sep}

8 WEEKS BEFORE:
   □ Book flights and accommodation
   □ Check passport validity (6+ months required)
   □ Apply for visa (if required)
   □ Book required vaccinations
   □ Purchase travel insurance

4 WEEKS BEFORE:
   □ Book major tours, events & activities
   □ Notify bank of travel dates
   □ Download offline maps & translation
   □ Research local SIM card options
   □ Buy event tickets in advance

1 WEEK BEFORE:
   □ Online check-in for flights
   □ Print/save all important documents
   □ Exchange some local currency
   □ Pack medications & prescriptions
   □ Charge all electronics and power bank

DAY BEFORE:
   □ Final packing check against list above
   □ Secure home (locks, lights, thermostat)
   □ Set mail hold & notify neighbours
   □ Share full itinerary with family/friends
   □ Set multiple alarms for departure


📱 ESSENTIAL APPS TO DOWNLOAD
{sep}
   • Google Maps (download offline map for destination)
   • Google Translate (download offline language pack)
   • XE Currency Converter
   • TripAdvisor / Yelp / TheFork
   • Local rideshare app (Grab, Bolt, Cabify, etc.)
   • Flightradar24 (flight tracker)
   • Your airline app
   • Golden Hour (photography timing)


🚨 EMERGENCY CONTACTS
{sep}
   • Local Emergency Services: [check destination-specific numbers]
   • Nearest Embassy/Consulate: [check gov.travel or embassy.gov]
   • Travel Insurance 24/7 Line: [your provider's emergency number]
   • Bank/Card Emergency: [keep card company international number]
   • Trusted Home Contact: [leave this itinerary with someone]


╔═══════════════════════════════════════════════════════════════════════════╗
║                  🌟 BON VOYAGE! HAVE AN AMAZING TRIP! 🌟                  ║
║                                                                           ║
║     "The world is a book, and those who do not travel read only one       ║
║                            page." — St. Augustine                         ║
╚═══════════════════════════════════════════════════════════════════════════╝

✨ Generated by AI Dream Vacation Planner  ✨
📧 Share this guide with your travel companions!
"""

    return {'travel_guide': guide}
